prompt.task:
-- 改动: App.tsx 在聊天界面头部新增教学状态指示器 --

在 `` 标签内部, 在消息列表上方 (约第 200 行), 插入:

{/* Phase 19-26: 教学状态指示器 */}
{state.sessionId && (


    {/* LLM 模式 */}
    {lastMsg?.llm_generated ? (

        LLM 教学

    ) : (

        规则教学

    )}
    {/* 难度 */}
    {lastMsg?.difficulty_contract?.level && (

        难度: {{
          easy: '简单', medium: '中等', hard: '困难'
        }[lastMsg.difficulty_contract.level as string] || lastMsg.difficulty_contract.level}

    )}
    {/* 策略 */}
    {lastMsg?.actionType && lastMsg.actionType !== 'awakening' && (
      策略: {lastMsg.actionType}
    )}
    {/* TTM 阶段 */}
    {state.ttmStage && (
      阶段: {state.ttmStage}
    )}

)}

需要在 App.tsx 中获取 lastMsg:

const lastMsg = state.messages[state.messages.length - 1];
